const rows = $input.all().map(i => i.json);
const cfg = {};
for (const r of rows) cfg[r.key] = r.value;
const d = new Date(); const runDate = d.toISOString().slice(0, 10);
return [{ json: { _config: cfg, _runDate: runDate } }];

const cfg = $('Parse Config').first().json._config || {};
const runDate = $('Parse Config').first().json._runDate;
const first = $input.first().json; const cols = Array.isArray(first) ? first : $input.all().map(i => i.json);
const byId = new Map();
const sqlText = (v) => (v === null || v === undefined || v === '') ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
const mapStatus = (name, excluido) => {
  const n = (name || '').toLowerCase();
  if (excluido || n.includes('anulada')) return 'cancelled';
  if (n === 'confirmado' || n === 'na casa') return 'confirmed';
  if (n === 'atendido' || n === 'executado') return 'completed';
  if (n === 'prof. faltou' || n === 'prof. ausente' || n === 'falta') return 'failed';
  if (n === 'a confirmar' || n === 'não confirmado' || n === 'nao confirmado') return 'pending';
  return 'pending';
};
const mapConfirmation = (name, status) => {
  const n = (name || '').toLowerCase();
  if (n === 'confirmado' || n === 'na casa' || n === 'atendido' || n === 'executado') return 'confirmed';
  if (n === 'não confirmado' || n === 'nao confirmado' || status === 'failed' || status === 'cancelled') return 'rejected';
  if (n === 'a confirmar') return 'not_sent';
  return cfg.appointments_initial_confirmation_status || 'not_sent';
};
for (const col of cols) {
  for (const ag of (col.agendamentos || [])) {
    const externalId = ag.idAgenda;
    const start = ag.horaInicio || null;
    if (!externalId || !start || start.slice(0, 10) !== runDate) continue;
    if (byId.has(externalId)) continue;
    const rawName = (ag.statusAgenda && ag.statusAgenda.nome) || null;
    const status = mapStatus(rawName, ag.excluido);
    const confirmationStatus = mapConfirmation(rawName, status);
    const rawPayload = {
      collaborator: { idColaboradorEmpresa: col.idColaboradorEmpresa || null, apelido: col.apelido || null, idCargo: col.idCargo || null },
      appointment: ag,
      runDate,
    };
    byId.set(externalId, {
      source_system: 'graces_agenda',
      external_appointment_id: externalId,
      contact_id: null,
      lead_id: null,
      scheduled_start: start,
      scheduled_end: ag.horaFim || null,
      status,
      confirmation_status: confirmationStatus,
      idempotency_key: `graces_agenda:${externalId}`,
      service_code: ag.idProdutoServico || null,
      service_name: ag.nomeServico || ag.descricao || null,
      unit_code: 'bf85c894-09c2-4122-b9fc-29efc20d2e2a',
      professional_code: col.idColaboradorEmpresa || ag.idColaboradorEmpresa || null,
      professional_name: col.apelido || null,
      client_name: ag.nomeCliente || null,
      external_client_id: ag.idCliente || null,
      external_order_id: ag.idComanda || null,
      raw_status_name: rawName,
      raw_payload: rawPayload,
      followup_enabled: cfg.appointments_followup_enabled === true,
      sql_source_system: sqlText('graces_agenda'),
      sql_external_appointment_id: sqlText(externalId),
      sql_service_code: sqlText(ag.idProdutoServico || null),
      sql_service_name: sqlText(ag.nomeServico || ag.descricao || null),
      sql_unit_code: sqlText('bf85c894-09c2-4122-b9fc-29efc20d2e2a'),
      sql_professional_code: sqlText(col.idColaboradorEmpresa || ag.idColaboradorEmpresa || null),
      sql_scheduled_start: sqlText(start),
      sql_scheduled_end: sqlText(ag.horaFim || null),
      sql_status: sqlText(status),
      sql_confirmation_status: sqlText(confirmationStatus),
      sql_idempotency_key: sqlText(`graces_agenda:${externalId}`),
      sql_client_name: sqlText(ag.nomeCliente || null),
      sql_raw_status_name: sqlText(rawName),
      sql_followup_enabled: cfg.appointments_followup_enabled === true ? 'true' : 'false',
      _safePayload: JSON.stringify(rawPayload).replace(/'/g, "''")
    });
  }
}
return Array.from(byId.values()).map(v => ({ json: v }));

const items = $input.all().map(i => i.json);
const eligible = items.filter(i => i.followup_enabled && i.confirmation_status === 'not_sent');
if (!eligible.length) return [];
eligible.sort((a, b) => new Date(a.scheduled_start) - new Date(b.scheduled_start));
const first = eligible[0];
const payload = {
  should_fail: false,
  workflow_action: 'send_confirmation_followup',
  appointment_id: first.id,
  external_appointment_id: first.external_appointment_id,
  scheduled_start: first.scheduled_start,
  status: first.status,
  confirmation_status: first.confirmation_status,
  client_name: first.client_name,
  service_name: first.service_name,
  raw_status_name: first.raw_status_name,
};
const idempotencyKey = `appointment-followup:${first.external_appointment_id}`;
return [{ json: {
  command_type: 'local_noop_success',
  target_system: 'local',
  entity_type: 'appointments',
  entity_id: first.id,
  external_appointment_id: first.external_appointment_id,
  idempotency_key: idempotencyKey,
  _safePayload: JSON.stringify(payload).replace(/'/g, "''"),
  _safeIdempotencyKey: idempotencyKey.replace(/'/g, "''"),
  _safeExternalAppointmentId: String(first.external_appointment_id).replace(/'/g, "''"),
} }];
